// ... existing imports and code ...

const Navigation = () => {
  // ... existing states ...
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState(null);

  // ... other existing code ...

  // Handle contact form submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    setSubmitError(null);

    try {
      const response = await fetch('https://andera.pythonanywhere.com/api/contact/', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          name: formData.name,
          email: formData.email,
          message: formData.message
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to submit form. Please try again later.');
      }

      const responseData = await response.json();
      console.log('Form submission successful:', responseData);
      
      setFormSubmitted(true);
      setFormData({ name: '', email: '', message: '' });
    } catch (error) {
      console.error('Form submission error:', error);
      setSubmitError(error.message || 'An unexpected error occurred. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  // ... rest of the component ...

  return (
    <>
      {/* ... existing navbar and initiative modal ... */}

      {/* Contact Modal */}
      <Modal 
        show={showContact} 
        onHide={() => setShowContact(false)}
        centered
        className="contact-modal"
      >
        <Modal.Header className="position-relative">
          <Modal.Title>Contact Us</Modal.Title>
          <button 
            type="button" 
            className="btn-close close-btn"
            onClick={() => setShowContact(false)}
            aria-label="Close"
            disabled={isSubmitting}
          ></button>
        </Modal.Header>
        <Modal.Body>
          {formSubmitted ? (
            <div className="alert alert-success text-center">
              <h4 className="text-success">Thank You!</h4>
              <p>Your message has been sent successfully.</p>
              <p>We'll contact you soon.</p>
            </div>
          ) : (
            <div>
              <div className="contact-info mb-4">
                <div className="d-flex align-items-center mb-3">
                  <i className="bi bi-telephone me-3 text-primary"></i>
                  <div>
                    <h6>Call Us</h6>
                    <p>+254 719 632 902</p>
                  </div>
                </div>
                <div className="d-flex align-items-center">
                  <i className="bi bi-envelope me-3 text-primary"></i>
                  <div>
                    <h6>Email Us</h6>
                    <p>contact@bukanimamatoto.org</p>
                  </div>
                </div>
              </div>
              
              <form onSubmit={handleSubmit}>
                <div className="mb-3">
                  <label htmlFor="name" className="form-label">Your Name</label>
                  <input
                    type="text"
                    id="name"
                    name="name"
                    className="form-control"
                    value={formData.name}
                    onChange={handleChange}
                    placeholder="Enter your name"
                    required
                    disabled={isSubmitting}
                  />
                </div>
                
                <div className="mb-3">
                  <label htmlFor="email" className="form-label">Email Address</label>
                  <input
                    type="email"
                    id="email"
                    name="email"
                    className="form-control"
                    value={formData.email}
                    onChange={handleChange}
                    placeholder="Enter your email"
                    required
                    disabled={isSubmitting}
                  />
                </div>
                
                <div className="mb-3">
                  <label htmlFor="message" className="form-label">Message</label>
                  <textarea
                    id="message"
                    name="message"
                    className="form-control"
                    rows={4}
                    value={formData.message}
                    onChange={handleChange}
                    placeholder="Your message here..."
                    required
                    disabled={isSubmitting}
                  ></textarea>
                </div>
                
                {submitError && (
                  <div className="alert alert-danger mb-3">
                    {submitError}
                  </div>
                )}
                
                <button 
                  type="submit"
                  className="btn btn-primary w-100 submit-btn"
                  disabled={isSubmitting}
                >
                  {isSubmitting ? (
                    <>
                      <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                      Sending...
                    </>
                  ) : (
                    <>
                      <i className="bi bi-send me-2"></i> Send Message
                    </>
                  )}
                </button>
              </form>
            </div>
          )}
        </Modal.Body>
      </Modal>

      {/* ... existing CSS ... */}
    </>
  );
};

export default Navigation;
